#include <bits/stdc++.h>
using namespace std;
struct Info{
    int first = -1, last = -1, prev = -1, max_gap = 0;
};
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> A(N+1);
        for(int i=1;i<=N;i++) cin>>A[i];
        unordered_map<int,Info> mp;
        mp.reserve(N*2);
        for(int i=1;i<=N;i++){
            int c=A[i];
            Info &inf = mp[c];
            if(inf.first==-1){
                inf.first = inf.last = inf.prev = i;
            }else{
                int gap = i - inf.prev;
                inf.max_gap = max(inf.max_gap, (gap+1)/2);
                inf.prev = i;
                inf.last = i;
            }
        }
        int bestClan = INT_MAX;
        int bestTime = INT_MAX;
        for(auto &p: mp){
            const Info &inf = p.second;
            int time = max({inf.first-1, N - inf.last, inf.max_gap});
            if(time < bestTime || (time==bestTime && p.first < bestClan)){
                bestTime = time;
                bestClan = p.first;
            }
        }
        cout<<bestClan<<' '<<bestTime<<"\n";
    }
    return 0;
}

