import java.io.*;
import java.util.*;

public class Main {
    static class Info {
        int first = -1, last = -1, prev = -1, maxGap = 0;
    }
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            int[] A = new int[N+1];
            for (int i = 1; i <= N; i++) A[i] = fs.nextInt();
            HashMap<Integer, Info> map = new HashMap<>(N*2);
            for (int i = 1; i <= N; i++) {
                int c = A[i];
                Info inf = map.get(c);
                if (inf == null) {
                    inf = new Info();
                    inf.first = inf.last = inf.prev = i;
                    map.put(c, inf);
                } else {
                    int gap = i - inf.prev;
                    inf.maxGap = Math.max(inf.maxGap, (gap + 1) / 2);
                    inf.prev = i;
                    inf.last = i;
                }
            }
            int bestClan = Integer.MAX_VALUE;
            int bestTime = Integer.MAX_VALUE;
            for (Map.Entry<Integer, Info> e : map.entrySet()) {
                Info inf = e.getValue();
                int time = Math.max(Math.max(inf.first - 1, N - inf.last), inf.maxGap);
                int clan = e.getKey();
                if (time < bestTime || (time == bestTime && clan < bestClan)) {
                    bestTime = time;
                    bestClan = clan;
                }
            }
            sb.append(bestClan).append(' ').append(bestTime).append('\n');
        }
        System.out.print(sb.toString());
    }
    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

