import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        A = [0] + [int(next(it)) for _ in range(N)]
        info = {}
        for i in range(1, N+1):
            c = A[i]
            if c not in info:
                info[c] = [i, i, i, 0]  # first, last, prev, max_gap
            else:
                first, last, prev, max_gap = info[c]
                gap = i - prev
                max_gap = max(max_gap, (gap + 1)//2)
                info[c] = [first, i, i, max_gap]
        best_clan = None
        best_time = None
        for clan, (first, last, _, max_gap) in info.items():
            time = max(first-1, N-last, max_gap)
            if best_time is None or time < best_time or (time == best_time and clan < best_clan):
                best_time = time
                best_clan = clan
        out_lines.append(f"{best_clan} {best_time}")
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

