let output = [];
for (let t = 0; t < T; t++) {
  const N = input[idx++];
  const info = new Map(); // clan -> [first, last, prev, maxGap]
  for (let i = 1; i <= N; i++) {
    const c = input[idx++];
    if (!info.has(c)) {
      info.set(c, [i, i, i, 0]);
    } else {
      const arr = info.get(c);
      const gap = i - arr[2];
      arr[3] = Math.max(arr[3], Math.floor((gap + 1) / 2));
      arr[1] = i; // last
      arr[2] = i; // prev
    }
  }
  let bestClan = Number.MAX_SAFE_INTEGER;
  let bestTime = Number.MAX_SAFE_INTEGER;
  for (const [clan, arr] of info.entries()) {
    const [first, last, , maxGap] = arr;
    const time = Math.max(first - 1, N - last, maxGap);
    if (time < bestTime || (time === bestTime && clan < bestClan)) {
      bestTime = time;
      bestClan = clan;
    }
  }
  output.push(bestClan + ' ' + bestTime);
